sourcesContent:
// Static content library — all 54 concepts, 3 tiers each
// tier: 'easy' (beginner), 'medium' (intermediate), 'hard' (advanced)

const content = {

  "Variables": {
    easy: {
      explanation: "A variable is a named container that stores a value in your program. You create a variable by giving it a name and assigning it a value using the equals sign. Python automatically figures out what type of data you're storing.",
      code: `# Creating variables
name = "Alice"
age = 25
height = 5.6
is_student = True

print(name)   # Alice
print(age)    # 25`,
      keypoints: [
        "Variables store data that can be used and changed throughout your program",
        "Use = to assign a value: x = 10 means x now holds the value 10",
        "Variable names should be descriptive — use student_name not sn"
      ],
      quiz: [
        { q: "What symbol is used to assign a value to a variable in Python?", opts: ["==", "=", "->", ":="], ans: 1 },
        { q: "Which variable name is valid in Python?", opts: ["2name", "my-name", "my_name", "my name"], ans: 2 },
        { q: "What does x = 5 do?", opts: ["Checks if x equals 5", "Stores 5 in variable x", "Prints 5", "Deletes x"], ans: 1 }
      ]
    },
    medium: {
      explanation: "Variables in Python are references to objects in memory. Multiple variables can point to the same object, and reassignment changes what the variable points to, not the object itself.",
      code: `x = [1, 2, 3]
y = x          # y points to same list
y.append(4)
print(x)       # [1, 2, 3, 4]

a = 10
b = a
b = 20
print(a)       # 10 — ints are immutable`,
      keypoints: [
        "Variables are references to objects, not the objects themselves",
        "Mutable objects (lists, dicts) share state when assigned to multiple variables",
        "Use id() to check if two variables point to the same object"
      ],
      quiz: [
        { q: "What is printed: x=5; y=x; y=10; print(x)?", opts: ["10", "5", "None", "Error"], ans: 1 },
        { q: "Which type is mutable in Python?", opts: ["int", "str", "tuple", "list"], ans: 3 },
        { q: "What does id(x) return?", opts: ["Value of x", "Type of x", "Memory address of x", "Length of x"], ans: 2 }
      ]
    },
    hard: {
      explanation: "Python variables use late binding in closures and follow LEGB scope resolution. Understanding variable internals — interning, reference counting, and the distinction between is and == — is critical for writing efficient code.",
      code: `import sys
x = 256; y = 256
print(x is y)    # True — small ints are interned

a = 257; b = 257
print(a is b)    # False — not interned

# Walrus operator
if n := len([1,2,3]):
    print(f"Length: {n}")`,
      keypoints: [
        "Python interns small integers (-5 to 256) and short strings for memory efficiency",
        "The walrus operator := assigns and returns a value in a single expression",
        "Use is for identity comparison, == for equality comparison"
      ],
      quiz: [
        { q: "What does the walrus operator := do?", opts: ["Assigns and returns value", "Compares identity", "Creates a copy", "Deletes variable"], ans: 0 },
        { q: "Which integers does Python intern by default?", opts: ["0 to 100", "-5 to 256", "0 to 256", "All integers"], ans: 1 },
        { q: "What is the difference between is and ==?", opts: ["No difference", "is checks identity, == checks equality", "is checks equality, == checks identity", "is is faster"], ans: 1 }
      ]
    }
  },

  "Data Types": {
    easy: {
      explanation: "Python has several built-in data types to represent different kinds of information. The main ones are integers (whole numbers), floats (decimal numbers), strings (text), and booleans (True/False). Python automatically detects the type when you assign a value.",
      code: `age = 25           # int
price = 9.99       # float
name = "Alice"     # str
active = True      # bool

print(type(age))   # <class 'int'>
print(type(name))  # <class 'str'>`,
      keypoints: [
        "int stores whole numbers, float stores decimal numbers",
        "Strings are text enclosed in single or double quotes",
        "Use type() to check what data type a variable holds"
      ],
      quiz: [
        { q: "What type is 3.14 in Python?", opts: ["int", "str", "float", "bool"], ans: 2 },
        { q: "What does type('hello') return?", opts: ["string", "<class 'str'>", "text", "char"], ans: 1 },
        { q: "Which is a boolean value?", opts: ["'True'", "1.0", "True", "yes"], ans: 2 }
      ]
    },
    medium: {
      explanation: "Python's type system is dynamic but strongly typed — types are checked at runtime and implicit conversions are limited. Type hints (PEP 484) add optional static typing for better code documentation and tooling support.",
      code: `from typing import Union

def process(val: Union[int, float]) -> str:
    return str(val * 2)

# Type conversion
x = int("42")       # str to int
y = float(10)       # int to float
z = str(3.14)       # float to str
print(isinstance(x, int))  # True`,
      keypoints: [
        "Type hints improve code readability but don't enforce types at runtime",
        "Use isinstance() for type checking instead of type() == comparisons",
        "Explicit conversion functions: int(), float(), str(), bool()"
      ],
      quiz: [
        { q: "What does int('3.14') return?", opts: ["3", "3.14", "ValueError", "3.0"], ans: 2 },
        { q: "Which checks type safely?", opts: ["type(x)==int", "isinstance(x, int)", "x.type==int", "checktype(x)"], ans: 1 },
        { q: "What is bool(0)?", opts: ["True", "False", "0", "None"], ans: 1 }
      ]
    },
    hard: {
      explanation: "Python's data model defines how types interact through dunder methods. Understanding type coercion rules, the numeric tower (numbers.Number hierarchy), and abstract base classes is essential for writing type-safe, extensible code.",
      code: `from numbers import Number
from abc import ABC, abstractmethod

class Vector(ABC):
    @abstractmethod
    def magnitude(self) -> float: ...

    def __add__(self, other):
        if not isinstance(other, type(self)):
            return NotImplemented
        return self._add(other)`,
      keypoints: [
        "Implement __eq__, __hash__, and __lt__ for full comparison support",
        "Return NotImplemented (not raise) from dunder methods to allow fallback",
        "Use ABC and abstractmethod to define type contracts"
      ],
      quiz: [
        { q: "What should __add__ return if types are incompatible?", opts: ["None", "False", "NotImplemented", "TypeError"], ans: 2 },
        { q: "Which module provides the numeric tower?", opts: ["typing", "numbers", "math", "abc"], ans: 1 },
        { q: "What makes a class abstract in Python?", opts: ["abstract keyword", "ABC base + abstractmethod", "interface keyword", "virtual methods"], ans: 1 }
      ]
    }
  },

  "Operators": {
    easy: {
      explanation: "Operators are symbols that perform operations on values. Python has arithmetic operators (+, -, *, /), comparison operators (==, !=, <, >), and logical operators (and, or, not). They are the building blocks of all expressions in Python.",
      code: `# Arithmetic
print(10 + 3)   # 13
print(10 // 3)  # 3 (floor division)
print(10 % 3)   # 1 (remainder)
print(2 ** 3)   # 8 (power)

# Comparison
print(5 > 3)    # True
print(5 == 5)   # True`,
      keypoints: [
        "// is floor division (rounds down), % gives the remainder",
        "== checks equality, = assigns a value — don't confuse them",
        "and/or/not combine boolean conditions logically"
      ],
      quiz: [
        { q: "What is 17 % 5?", opts: ["3", "2", "12", "85"], ans: 1 },
        { q: "What does ** do?", opts: ["Multiply", "Floor divide", "Power/exponent", "Modulo"], ans: 2 },
        { q: "What is True and False?", opts: ["True", "False", "None", "Error"], ans: 1 }
      ]
    },
    medium: {
      explanation: "Python operators follow precedence rules (PEMDAS-like) and support augmented assignment (+=, -=). Bitwise operators work on integer binary representations and are commonly used in flags, masks, and performance-critical code.",
      code: `x = 15  # 1111 in binary
y = 9   # 1001 in binary

print(x & y)   # 9  (AND)
print(x | y)   # 15 (OR)
print(x ^ y)   # 6  (XOR)
print(x >> 1)  # 7  (right shift)
print(~x)      # -16 (NOT)`,
      keypoints: [
        "Bitwise AND (&) keeps bits where both are 1; OR (|) keeps bits where either is 1",
        "Left shift (<<) multiplies by 2, right shift (>>) divides by 2",
        "Use parentheses to make precedence explicit and avoid bugs"
      ],
      quiz: [
        { q: "What is 5 & 3?", opts: ["7", "1", "15", "0"], ans: 1 },
        { q: "What does x <<= 2 do?", opts: ["Multiplies x by 2", "Multiplies x by 4", "Divides x by 4", "Shifts right"], ans: 1 },
        { q: "What is 6 ^ 3?", opts: ["5", "7", "18", "0"], ans: 0 }
      ]
    },
    hard: {
      explanation: "Python's operator model is fully customisable through dunder methods. Operator overloading, reflected operators (__radd__), and in-place operators (__iadd__) give complete control over how custom types interact with Python's operator syntax.",
      code: `class Money:
    def __init__(self, amount, currency="GBP"):
        self.amount = amount
        self.currency = currency

    def __add__(self, other):
        if self.currency != other.currency:
            raise ValueError("Currency mismatch")
        return Money(self.amount + other.amount, self.currency)

    def __repr__(self):
        return f"{self.currency} {self.amount:.2f}"`,
      keypoints: [
        "Implement __radd__ for right-side operations: 5 + obj calls obj.__radd__(5)",
        "__iadd__ enables += with in-place mutation for performance",
        "Always check type compatibility in dunder methods before operating"
      ],
      quiz: [
        { q: "When is __radd__ called?", opts: ["obj + 5", "5 + obj when obj.__add__ fails", "Always", "Never"], ans: 1 },
        { q: "What enables += in-place behaviour?", opts: ["__add__", "__iadd__", "__plus__", "__set__"], ans: 1 },
        { q: "What should __add__ return on type mismatch?", opts: ["None", "False", "NotImplemented", "0"], ans: 2 }
      ]
    }
  },

  "If/Else": {
    easy: {
      explanation: "If/else statements let your program make decisions. If a condition is True, one block of code runs; otherwise, the else block runs. This is how you add logic and branching to your programs.",
      code: `age = 18

if age >= 18:
    print("You can vote")
else:
    print("Too young to vote")

# One-line shorthand
status = "adult" if age >= 18 else "minor"`,
      keypoints: [
        "The if block runs when the condition is True, else runs when it's False",
        "Indentation (4 spaces) defines what's inside each block",
        "You can write simple if/else on one line using a ternary expression"
      ],
      quiz: [
        { q: "What runs when an if condition is False?", opts: ["if block", "else block", "Nothing", "Error"], ans: 1 },
        { q: "What defines a block in Python?", opts: ["Curly braces", "Indentation", "Brackets", "BEGIN/END"], ans: 1 },
        { q: "What is x = 5 if True else 10?", opts: ["5", "10", "True", "Error"], ans: 0 }
      ]
    },
    medium: {
      explanation: "Python evaluates conditions using truthiness — any object can be evaluated as True or False. Understanding falsy values and short-circuit evaluation helps write concise, efficient conditional logic.",
      code: `# Falsy values
falsy = [0, "", [], {}, None, False]
for val in falsy:
    print(bool(val))   # All False

# Short-circuit evaluation
name = None
display = name or "Anonymous"  # "Anonymous"

# Chained comparisons
x = 5
print(1 < x < 10)   # True`,
      keypoints: [
        "Falsy values: 0, empty strings/lists/dicts, None, and False",
        "or returns first truthy value; and returns first falsy value",
        "Python supports chained comparisons: 1 < x < 10 is valid"
      ],
      quiz: [
        { q: "What is bool([])?", opts: ["True", "False", "None", "Error"], ans: 1 },
        { q: "What does None or 'default' return?", opts: ["None", "True", "'default'", "False"], ans: 2 },
        { q: "Is 1 < 5 < 10 valid Python?", opts: ["Yes", "No", "Only in Python 3", "Syntax error"], ans: 0 }
      ]
    },
    hard: {
      explanation: "Structural pattern matching (match/case, PEP 634) extends conditional logic to destructuring and type matching. Combined with guard clauses and the walrus operator, Python offers expressive control flow for complex decision trees.",
      code: `def classify(point):
    match point:
        case (0, 0):
            return "origin"
        case (x, 0) if x > 0:
            return f"positive x-axis at {x}"
        case (0, y):
            return f"y-axis at {y}"
        case (x, y):
            return f"point ({x}, {y})"

print(classify((3, 0)))  # positive x-axis at 3`,
      keypoints: [
        "match/case supports structural pattern matching with destructuring",
        "Guard clauses (if after case) add conditions to patterns",
        "Early returns reduce nesting and improve readability over deep if/else"
      ],
      quiz: [
        { q: "What Python version introduced match/case?", opts: ["3.8", "3.9", "3.10", "3.11"], ans: 2 },
        { q: "What is a guard clause in match/case?", opts: ["Default case", "if condition after case pattern", "Break statement", "Return value"], ans: 1 },
        { q: "What does case _ match?", opts: ["Nothing", "Only None", "Everything (wildcard)", "Only strings"], ans: 2 }
      ]
    }
  },

  "For Loop": {
    easy: {
      explanation: "A for loop repeats a block of code for each item in a sequence. You can loop over lists, strings, ranges, and any iterable. The loop variable takes each value one at a time automatically.",
      code: `# Loop over a list
fruits = ["apple", "banana", "cherry"]
for fruit in fruits:
    print(fruit)

# Loop with range
for i in range(5):
    print(i)    # 0, 1, 2, 3, 4`,
      keypoints: [
        "for x in collection loops through every item one at a time",
        "range(n) generates numbers from 0 to n-1",
        "range(start, stop, step) gives more control over the sequence"
      ],
      quiz: [
        { q: "How many times does range(5) iterate?", opts: ["4", "5", "6", "0"], ans: 1 },
        { q: "What does range(2, 8, 2) produce?", opts: ["2,4,6,8", "2,4,6", "2,3,4,5,6,7", "0,2,4,6"], ans: 1 },
        { q: "Can you loop over a string with for?", opts: ["Yes", "No", "Only in Python 3", "Only with list()"], ans: 0 }
      ]
    },
    medium: {
      explanation: "Python's for loop works with any iterable through the iterator protocol. enumerate() adds indices, zip() pairs sequences, and comprehensions provide a compact loop syntax for transforming data.",
      code: `names = ["Alice", "Bob", "Charlie"]
scores = [92, 87, 95]

# enumerate + zip together
for i, (name, score) in enumerate(zip(names, scores)):
    print(f"{i+1}. {name}: {score}")

# Comprehension
squares = [x**2 for x in range(10) if x % 2 == 0]`,
      keypoints: [
        "enumerate(iterable) yields (index, value) pairs",
        "zip(a, b) pairs elements from two iterables together",
        "List comprehensions are faster and more readable than equivalent for loops"
      ],
      quiz: [
        { q: "What does enumerate(['a','b']) yield?", opts: ["['a','b']", "(0,'a'),(1,'b')", "0,1", "Error"], ans: 1 },
        { q: "What does zip([1,2],[3,4]) produce?", opts: ["[1,2,3,4]", "(1,3),(2,4)", "[1,3],[2,4]", "Error"], ans: 1 },
        { q: "What is [x*2 for x in range(3)]?", opts: ["[0,2,4]", "[1,2,3]", "[2,4,6]", "[0,1,2]"], ans: 0 }
      ]
    },
    hard: {
      explanation: "Advanced iteration uses itertools for memory-efficient processing of large datasets. Understanding lazy evaluation, the iterator protocol (__iter__, __next__), and generator-based loops is key for high-performance Python.",
      code: `import itertools

data = range(1_000_000)

# Lazy chaining — no memory allocation
result = itertools.islice(
    filter(lambda x: x % 2 == 0,
           map(lambda x: x ** 2, data)),
    10
)
print(list(result))  # First 10 even squares`,
      keypoints: [
        "itertools functions return lazy iterators — data is processed on demand",
        "islice() limits iteration without materialising the full sequence",
        "Chaining map/filter/islice avoids intermediate list creation"
      ],
      quiz: [
        { q: "What does itertools.islice(it, 5) do?", opts: ["Skips 5", "Takes first 5", "Shuffles", "Reverses"], ans: 1 },
        { q: "Which is more memory efficient for 1M items?", opts: ["list comprehension", "generator expression", "Same", "Depends on type"], ans: 1 },
        { q: "What method must an iterator implement?", opts: ["__loop__", "__next__", "__yield__", "__step__"], ans: 1 }
      ]
    }
  },

  "While Loop": {
    easy: {
      explanation: "A while loop keeps running as long as a condition is True. It's used when you don't know in advance how many times you need to repeat something. Always make sure the condition eventually becomes False or the loop will run forever.",
      code: `count = 0
while count < 5:
    print(count)
    count += 1

# User input loop
while True:
    answer = input("Type 'quit' to stop: ")
    if answer == "quit":
        break`,
      keypoints: [
        "while condition: keeps looping until condition becomes False",
        "Always update the loop variable or condition to avoid infinite loops",
        "while True with break is used for loops that check condition in the middle"
      ],
      quiz: [
        { q: "When does a while loop stop?", opts: ["After 10 iterations", "When condition is False", "When condition is True", "Never"], ans: 1 },
        { q: "What causes an infinite loop?", opts: ["Using break", "Condition never becomes False", "Using continue", "Empty body"], ans: 1 },
        { q: "What does while True mean?", opts: ["Loop once", "Loop forever until break", "Loop while True exists", "Syntax error"], ans: 1 }
      ]
    },
    medium: {
      explanation: "While loops support else clauses that run when the condition becomes False naturally (not via break). This pattern is useful for search algorithms where you need to know if a loop completed without finding a result.",
      code: `# while/else pattern
target = 7
nums = [1, 3, 5, 9, 11]
i = 0
while i < len(nums):
    if nums[i] == target:
        print(f"Found at {i}")
        break
    i += 1
else:
    print("Not found")  # Runs if no break`,
      keypoints: [
        "while/else: the else block runs only if the loop exits normally (no break)",
        "This pattern cleanly handles 'not found' cases in search loops",
        "Use a flag variable as an alternative to while/else for clarity"
      ],
      quiz: [
        { q: "When does while/else execute the else?", opts: ["Always", "When break is hit", "When no break occurs", "Never"], ans: 2 },
        { q: "What is the main risk of while loops?", opts: ["Too slow", "Infinite loops", "Memory errors", "Syntax errors"], ans: 1 },
        { q: "Which is better for known iteration count?", opts: ["while", "for", "Both equal", "Neither"], ans: 1 }
      ]
